.load extensions/docx-meta/target/wasm32-wasip2/release/docx_meta_extension.component.wasm

/* docx-meta smoke harness.
 *
 * Fixtures (all hex literals, byte-identical across rebuilds
 * thanks to zero-mtime ZIP entries):
 *   docx: minimal OOXML wordprocessing package
 *     title=Test Document, author=Test Author,
 *     created=2024-01-15T10:30:45Z, modified=2024-01-16T11:30:45Z,
 *     Pages=3, Words=42, body=2 paragraphs.
 *   xlsx: minimal spreadsheet, 1 sheet, sharedStrings=[Alpha,Beta]
 *     2 rows x 2 cols = 4 cell <v> values.
 *   pptx: minimal presentation, 2 slides, slide1=Slide One Title,
 *     slide2=Slide Two Content.
 *   notooxml: a plain zip with foo.txt only (valid ZIP, no OOXML parts)
 *   random: 32 bytes of 0xAA (not a ZIP at all). */

------------------------------------------------------------------
-- Acceptance 1: docx fixture -> every accessor returns its field
------------------------------------------------------------------
SELECT docx_format(x'');
SELECT docx_title(x'');
SELECT docx_author(x'');
SELECT docx_created(x'');
SELECT docx_modified(x'');
SELECT docx_page_count(x'');
SELECT docx_word_count(x'');
SELECT docx_text_content(x'');

------------------------------------------------------------------
-- Acceptance 2: xlsx fixture -> sheet count, shared strings text,
-- cell count substitutes for word_count.
------------------------------------------------------------------
SELECT docx_format(x'');
SELECT docx_title(x'');
SELECT docx_author(x'');
SELECT docx_page_count(x'');
SELECT docx_word_count(x'');
SELECT docx_text_content(x'');

------------------------------------------------------------------
-- Acceptance 3: pptx fixture -> slide count, slide text dump.
------------------------------------------------------------------
SELECT docx_format(x'');
SELECT docx_title(x'');
SELECT docx_author(x'');
SELECT docx_page_count(x'');
SELECT docx_word_count(x'');
SELECT docx_text_content(x'');

------------------------------------------------------------------
-- Acceptance 4: docx_metadata returns parseable JSON
------------------------------------------------------------------
SELECT json_extract(docx_metadata(x''), '$.format');
SELECT json_extract(docx_metadata(x''), '$.title');
SELECT json_extract(docx_metadata(x''), '$.page_count');
SELECT json_extract(docx_metadata(x''), '$.word_count');
SELECT json_extract(docx_metadata(x''), '$.format');
SELECT json_extract(docx_metadata(x''), '$.format');

------------------------------------------------------------------
-- Acceptance 5: valid ZIP without OOXML parts -> every fn NULL
------------------------------------------------------------------
SELECT docx_format(x'504B0304140000000800AC76D45C8C1B0A85130000001100000007000000666F6F2E747874CB2A2D2E514854C8CB2FCA4DCC51A8CA2C0000504B01021403140000000800AC76D45C8C1B0A851300000011000000070000000000000000000000800100000000666F6F2E747874504B0506000000000100010035000000380000000000');
SELECT docx_title(x'504B0304140000000800AC76D45C8C1B0A85130000001100000007000000666F6F2E747874CB2A2D2E514854C8CB2FCA4DCC51A8CA2C0000504B01021403140000000800AC76D45C8C1B0A851300000011000000070000000000000000000000800100000000666F6F2E747874504B0506000000000100010035000000380000000000');
SELECT docx_author(x'504B0304140000000800AC76D45C8C1B0A85130000001100000007000000666F6F2E747874CB2A2D2E514854C8CB2FCA4DCC51A8CA2C0000504B01021403140000000800AC76D45C8C1B0A851300000011000000070000000000000000000000800100000000666F6F2E747874504B0506000000000100010035000000380000000000');
SELECT docx_text_content(x'504B0304140000000800AC76D45C8C1B0A85130000001100000007000000666F6F2E747874CB2A2D2E514854C8CB2FCA4DCC51A8CA2C0000504B01021403140000000800AC76D45C8C1B0A851300000011000000070000000000000000000000800100000000666F6F2E747874504B0506000000000100010035000000380000000000');
SELECT docx_metadata(x'504B0304140000000800AC76D45C8C1B0A85130000001100000007000000666F6F2E747874CB2A2D2E514854C8CB2FCA4DCC51A8CA2C0000504B01021403140000000800AC76D45C8C1B0A851300000011000000070000000000000000000000800100000000666F6F2E747874504B0506000000000100010035000000380000000000');

------------------------------------------------------------------
-- Acceptance 6: random bytes -> every fn NULL
------------------------------------------------------------------
SELECT docx_format(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_title(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_author(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_created(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_modified(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_page_count(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_word_count(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_text_content(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');
SELECT docx_metadata(x'AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA');

------------------------------------------------------------------
-- Acceptance 7: NULL input -> every fn NULL
------------------------------------------------------------------
SELECT docx_format(NULL);
SELECT docx_title(NULL);
SELECT docx_page_count(NULL);

------------------------------------------------------------------
-- Acceptance 8: meta version is non-empty TEXT
------------------------------------------------------------------
SELECT length(docx_meta_version()) > 0;
